module counter8bit_up_sync (
    input clk,
    input rst,
    input en,
    output [7:0] q
);

    reg [7:0] obf_q_reg;

    always @(posedge clk) begin
        if (rst)
            obf_q_reg <= 8'b00000000;
        else if (en)
            obf_q_reg <= obf_q_reg + 1;
    end

    assign q = obf_q_reg;

endmodule
